import { useEffect, useState } from "react";
import BannerCarousel from "../components/BannerCarousel";
import List from "../components/List/List";
import ErrorMessage from "../components/common/ErrorMessage/ErrorMessage";
import Loading from "../components/common/Loading/Loading";
import homeImages from "../data/homeImages.json";
import { fetchProducts } from "../services/productService";
import Button from "../components/common/Button";

export default function Home() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const loadProducts = async () => {
    setLoading(true);
    setError(null);
    const productsData = await fetchProducts();
    setProducts(productsData.products);
  };

  useEffect(() => {
    let ignore = false;
    (async () => {
      try {
        await loadProducts();
        set
      } catch (e) {
        if (!ignore) {
          setError("No se pudieron cargar los productos. Intenta más tarde.");
          console.error(e);
          setProducts([]);
          setLoading(false);
        }
      }
    })();


    return () => {
      ignore = true;
    };
  }, []);

  return (
    <div>
      <BannerCarousel banners={homeImages} />
      {loading ? (
        <Loading>Cargando productos...</Loading>
      ) : error ? (
        <ErrorMessage>
          <span>{error}</span>
          <Button
            type="button"
            variant="primary"
            onClick={(e) => {
              loadProducts().then(setLoading(false)).catch((err) => {
                setError("No se pudieron cargar los productos. Intenta más tarde.");
                console.error(e);
                setProducts([]);
                setLoading(false);
              });
            }}
          >
            Volver a cargar
          </Button>
        </ErrorMessage>
      ) : products.length > 0 ? (
        <List
          title="Productos recomendados"
          products={products}
          layout="grid"
        />
      ) : (
        <ErrorMessage>No hay productos en el catálogo</ErrorMessage>
      )}
    </div>
  );
}
